@app.post(
    "/internal/tokens",
    response_model=TokenCreateResponse,
    include_in_schema=False,
)
async def create_token(
    request: Request,
    body: TokenCreateRequest,
    redis_client: redis.Redis = Depends(get_redis),
):
    """
    Internal endpoint to create a token and store it in Redis.
    In production, this would be behind an internal network / mTLS / API key.
    """
    internal_secret = os.environ.get("INTERNAL_API_SECRET")
    if not internal_secret:
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Server misconfigured")

    provided_secret = request.headers.get("X-Internal-Secret", "")
    if not hmac.compare_digest(provided_secret.encode("utf-8"), internal_secret.encode("utf-8")):
        raise HTTPException(status_code=status.HTTP_403_FORBIDDEN, detail="Forbidden")

    raw_token = secrets.token_urlsafe(48)

    token_hash = _hash_token(raw_token)
    redis_key = f"{TOKEN_PREFIX}{token_hash}"

    ttl = min(body.ttl or TOKEN_TTL, 86400)
    expires_at = datetime.utcnow().timestamp() + ttl

    token_data = {
        "user_id": body.user_id,
        "client_id": body.client_id,
        "scopes": ",".join(body.scopes),
        "expires_at": str(expires_at),
    }

    try:
        async with redis_client.pipeline(transaction=True) as pipe:
            pipe.hset(redis_key, mapping=token_data)
            pipe.expire(redis_key, ttl)
            await pipe.execute()
    except redis.RedisError as e:
        logger.error(f"Redis error creating token: {e}")
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Token service temporarily unavailable",
        )

    logger.info("Token created for user_id=%s, client_id=%s, ttl=%d", body.user_id, body.client_id, ttl)

    return TokenCreateResponse(access_token=raw_token, expires_in=ttl)


@app.post("/internal/tokens/revoke", include_in_schema=False)
async def revoke_token(
    request: Request,
    token: str,
    redis_client: redis.Redis = Depends(get_redis),
):
    """Revoke a token by removing it from Redis."""
    internal_secret = os.environ.get("INTERNAL_API_SECRET")
    if not internal_secret:
        raise HTTPException(status_code=status.HTTP_500_INTERNAL_SERVER_ERROR, detail="Server misconfigured")

    provided_secret = request.headers.get("X-Internal-Secret", "")
    if not hmac.compare_digest(provided_secret.encode("utf-8"), internal_secret.encode("utf-8")):
        raise HTTPException(status_code=status.HTTP_403_FORBIDDEN, detail="Forbidden")

    if not _validate_token_format(token):
        raise HTTPException(status_code=status.HTTP_400_BAD_REQUEST, detail="Invalid token format")

    token_hash = _hash_token(token)
    redis_key = f"{TOKEN_PREFIX}{token_hash}"

    try:
        deleted = await redis_client.delete(redis_key)
    except redis.RedisError as e:
        logger.error(f"Redis error revoking token: {e}")
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Token service temporarily unavailable",
        )

    if deleted:
        logger.info("Token revoked (hash: %s...)", token_hash[:8])
        return {"status": "revoked"}
    else:
        return {"status": "not_found"}


